qry:select.qry:xquery:
					for $r in sql('
	SELECT 
			CV.oi_cv,
			CV.c_nro_doc, 
			CV.d_ape_y_nom,
			SEC.policy
	FROM 
		SDP01_CV as CV,
		{%?('##idioma##'!='') {% SDP01_IDIOMAS_CV as IDIOMA, %} {% %} %}							
		{%?('##informatica##'!='') {% SDP01_INFORMATICA AS INF, %} {% %} %}
		{%?('##experiencia##'!='') {% SDP01_EXPERIENCIA AS EXP, %} {% %} %}
		{%?('##estudio##'!='' OR '##area_estudio##'!='') {% SDP01_ESTUDIOS_CV AS EST, %} {% %} %}				
		{%?('##area_laboral##'!='') {% SDP01_AREAS_CV AS AREA, %} {% %} %} 
		{%?('##aviso##'!='') {% SDP01_POSTU_CV AS AVISO, %} {% %} %}
		NMD_SECURITY(class=\'NucleusRH.Base.SeleccionDePostulantes.CVs.CV\') AS SEC			

	JOIN 
		CV.oi_cv LEFT OUTER SEC.id				
		{%?('##idioma##'!='') {% , CV.oi_cv INNER IDIOMA.oi_cv %} {% %} %}							
		{%?('##informatica##'!='') {% , CV.oi_cv INNER INF.oi_cv %} {% %} %}
		{%?('##experiencia##'!='') {% , CV.oi_cv INNER EXP.oi_cv %} {% %} %}				
		{%?('##estudio##'!='' OR '##area_estudio##'!='') {% , CV.oi_cv INNER EST.oi_cv %} {% %} %}								
		{%?('##area_laboral##'!='') {% , CV.oi_cv INNER AREA.oi_cv %} {% %} %} 
		{%?('##aviso##'!='') {% , CV.oi_cv INNER AVISO.oi_cv %} {% %} %}			

	WHERE 1=1						
		{%?('##estado##'!='') {% and CV.c_estado = \'##estado##\' %} {% %} %}			
		{%?('##localidad##'!='') {% and CV.d_localidad = \'##localidad##\' %} {% %} %}
		{%?('##idioma##'!='') {% and IDIOMA.oi_idioma = ##idioma## %} {% %} %}
		{%?('##informatica##'!='') {% and INF.oi_informatica = ##informatica## %} {% %} %}
		{%?('##experiencia##'!='') {% and EXP.oi_puesto_exp = ##experiencia## %} {% %} %}
		{%?('##estudio##'!='') {% and EST.oi_nivel_estudio = ##estudio## %} {% %} %}
		{%?('##area_estudio##'!='') {% and EST.oi_area_est = ##area_estudio## %} {% %} %}
		{%?('##area_laboral##'!='') {% and AREA.oi_area = ##area_laboral## %} {% %} %} 
		{%?('##aviso##'!='') {% and AVISO.oi_aviso = ##aviso## %} {% %} %}
		{%?('##edad_desde##'!='') {% and floor(GETYEAR(NOW())-GETYEAR(CV.f_nacim)+GETMONTH(NOW())*0.0833333-GETMONTH(CV.f_nacim)*0.0833333) >= ##edad_desde## %} {% %} %}
		{%?('##edad_hasta##'!='') {% and floor(GETYEAR(NOW())-GETYEAR(CV.f_nacim)+GETMONTH(NOW())*0.0833333-GETMONTH(CV.f_nacim)*0.0833333) <= ##edad_hasta## %} {% %} %}
		{%?('##oi_provincia##'!='') {% and CV.oi_provincia = \'##oi_provincia##\' %} {% %} %}
		{%?('##tipoPostulante##'='I') {% AND ISNOTNULL(CV.oi_personal) %} {% %} %}
		{%?('##tipoPostulante##'='E') {% AND ISNULL(CV.oi_personal) %} {% %} %}
	GROUP BY 
		CV.oi_cv,
		CV.c_nro_doc, 
		CV.d_ape_y_nom,
		SEC.policy
	ORDER BY 
		d_ape_y_nom ASC
')/ROWS/ROW

form:Form.form:Scripts:
		function SendToServer()
{       
GetProxy().StoreService().SetUserStore("PER_IDsPersonas", array2stringcustom(arrB, "ROWS", "ROW"));
return true;
}

function Filtrar()  
{                   

 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay personas filtradas.");
 		return false;
 	}

 	if (Ctrl("list2").TotalRowsCount()>100)
 	{             
 		alert("Hay demasiados registros seleccionados, afine la búsqueda.");
 		return false;
 	}
SendToServer();
Ctrl("main").DoEvent("FILTER");
}

function enable_custom_buttons()
{
if (Ctrl("list2"))
CtrlEnabled("btnFILTER", Ctrl("list2").TotalRowsCount()?true:false);
}



function internal_load()
{ 

  var auxArr;  
auxArr = exec_qry();	
if (auxArr==null)	
 return;
arrB = auxArr; 
remove(arrB, arrA);	
refreshList("list2", arrB);
}

function internal_filter()
{

  var auxArr;
auxArr = exec_qry();
if (auxArr==null) return;  

intersect(arrB, auxArr);	
refreshList("list2", arrB);
}

function internal_loadadd()
{

  var auxArr;
auxArr = exec_qry();
if (auxArr==null) return;  

remove(auxArr, arrA);		
union(arrB, auxArr);
refreshList("list2", arrB);
}

function internal_find()
{

  var auxArr;
  var key;
auxArr = exec_qry();
if (auxArr==null) return;  

intersect(auxArr, arrB);
key="";
for (key in auxArr) break;
if (key!="") 
Ctrl("list2").SetXValue(key.substr(1));
else
alert("No se encontro ningun registro.");
}
